// Build the master email writing prompt for Claude
const config = $input.first().json;
const contacts = $('Webhook - Write Email').all();
const results = [];

for (const item of contacts) {
  const c = item.json;

  // Build email sequence (4 emails)
  const sequencePrompt = `You are Harvey Spectre, the world's most effective cold email writer. You write emails that sound like they came from a real human who genuinely researched the prospect - never templated, never salesy, always specific.

CLIENT BRAND: ${config.client_brand}
CLIENT USP: ${config.client_usp}
PROOF POINTS: ${config.client_proof_points}
DESIRED TONE: ${config.desired_tone}
TOPICS TO AVOID: ${config.topics_to_avoid}
MAX WORDS PER EMAIL: ${config.max_email_words}

PROSPECT INTELLIGENCE:
- Name: ${c.full_name}
- Title: ${c.job_title}
- Company: ${c.company_name}
- Contact Rank: ${c.contact_rank || 1} (1=primary decision maker, 2=secondary, 3=tertiary)
- Personal Hook: ${c.personal_hook || 'N/A'}
- Company Trigger: ${c.company_trigger || 'N/A'}
- Pain Hypothesis: ${c.pain_hypothesis || 'Sourcing consistent quality coffee at scale with competitive pricing'}
- Connection Angle: ${c.connection_angle || 'Origin-roasted coffee at 30-40% lower costs'}
- Recommended Tone: ${c.recommended_tone || 'data-driven'}
- Ice Breaker: ${c.ice_breaker || ''}
- Research Confidence: ${c.research_confidence || 'low'}

WRITE A 4-EMAIL SEQUENCE:

Email 1 (Initial outreach - Day 0):
- Use PAS framework (Problem-Agitate-Solve)
- Open with the personal hook or ice breaker if available
- ONE specific pain point connected to their role
- ONE proof point
- Soft CTA: "Would you be open to reviewing samples?" or similar
- 50-100 words, plain text, no links

Email 2 (Follow-up 1 - Day 3):
- Reference Email 1 briefly ("Sent you a note about...")
- NEW angle or proof point not mentioned in Email 1
- Add a data point or social proof
- Same soft CTA
- 40-80 words

Email 3 (Follow-up 2 - Day 10):
- Completely different angle
- Share an industry insight or market trend
- Connect it back to the offer
- 40-80 words

Email 4 (Breakup - Day 17):
- Permission-based close
- "Seems like timing isn't right - totally understand"
- Leave door open
- 30-60 words

RULES:
- NEVER use "I hope this email finds you well" or any filler
- NEVER use exclamation marks
- NEVER use corporate buzzwords (synergy, leverage, optimize, etc.)
- First name only in greeting ("Hi Sarah," not "Dear Ms. Johnson")
- No HTML, no images, no bold/italic
- Maximum ONE link in the entire sequence (preferably zero)
- Each email must be standalone (recipient may not have read previous ones)
- Sound like a real person, not a marketing bot
- Use short sentences. Punchy.
- Subject lines: 3-6 words, lowercase, no punctuation hype

Return as JSON:
{
  "emails": [
    {
      "sequence_number": 1,
      "send_day": 0,
      "subject": "subject line here",
      "body": "email body here",
      "word_count": 85,
      "framework": "PAS"
    },
    ...
  ]
}

Return ONLY the JSON, no markdown formatting.`;

  results.push({
    json: {
      ...c,
      email_prompt: sequencePrompt,
      client_config: config
    }
  });
}

return results;

// Parse email sequence and create individual email records
const items = $input.all();
const contacts = $('Build Email Prompt').all();
const allEmails = [];

for (let i = 0; i < items.length; i++) {
  const response = items[i].json;
  const contact = contacts[i]?.json || {};
  const content = response.content?.[0]?.text || '';

  let emailSequence = { emails: [] };
  try {
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      emailSequence = JSON.parse(jsonMatch[0]);
    }
  } catch (e) {
    // Fallback: create a basic email
    emailSequence = {
      emails: [{
        sequence_number: 1,
        send_day: 0,
        subject: `coffee sourcing from Vietnam`,
        body: `Hi ${contact.first_name || 'there'},\n\nSourcing consistent roasted coffee at scale is a challenge many buyers face. We operate a PROBAT P60 roastery in Vietnam with 40-50 MT monthly capacity at 30-40% lower landed costs than European roasters.\n\nWould you be open to reviewing samples?\n\nBest,\nHarvey`,
        word_count: 45,
        framework: 'PAS'
      }]
    };
  }

  // Create individual records for each email in the sequence
  const { email_prompt, client_config, ...cleanContact } = contact;

  for (const email of emailSequence.emails || []) {
    allEmails.push({
      json: {
        // Contact info
        full_name: cleanContact.full_name,
        email: cleanContact.email,
        company_name: cleanContact.company_name,
        job_title: cleanContact.job_title,
        contact_rank: cleanContact.contact_rank || 1,

        // Email content
        sequence_number: email.sequence_number,
        send_day: email.send_day,
        subject: email.subject,
        body: email.body,
        word_count: email.word_count,
        framework: email.framework,

        // Status
        status: 'draft',
        approved: false,
        sent: false,
        pipeline_stage: 'email_drafted',
        drafted_at: new Date().toISOString(),

        // Scheduling
        scheduled_send_date: null,
        actual_send_date: null,

        // Tracking
        campaign_id: `${cleanContact.company_name?.replace(/[^a-zA-Z0-9]/g, '_')}_${Date.now()}`,
        thread_id: `thread_${cleanContact.full_name?.replace(/[^a-zA-Z0-9]/g, '_')}`
      }
    });
  }
}

return allEmails;
